#include "tall_skinny_matrix_multiplication_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

// UB model: A tile: tileM * tileK, B tile: tileK * tileN, C tile: tileM * tileN,
//   plus workspace for double buffering (factor 2).
// Total floats ~ 2 * (tileM * tileK + tileK * tileN + tileM * tileN)
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN = 32;  // align to 32 floats (128 bytes)

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1) / b;
}

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t compute_tileM(uint32_t M, uint32_t K, uint32_t N, uint32_t tileK, uint32_t tileN) {
    // max floats from UB: 2*(tileM*tileK + tileK*tileN + tileM*tileN) <= UB_BUDGET/4
    uint32_t max_floats = UB_BUDGET_BYTES / 4 / 2;  // divided by double buffer factor
    uint32_t numerator = max_floats - tileK * tileN;
    uint32_t denominator = tileK + tileN;
    if (denominator == 0) return 1;
    uint32_t tileM = numerator / denominator;
    tileM = AlignDown(tileM, ALIGN);
    if (tileM == 0) tileM = ALIGN;
    if (tileM > M) tileM = AlignDown(M, ALIGN);
    if (tileM == 0) tileM = M;
    return tileM;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    TallSkinnyMatrixMultiplicationCustomTilingData tiling;

    const auto &shapeA = context->GetInputShape(0)->GetOriginShape();
    const auto &shapeB = context->GetInputShape(1)->GetOriginShape();
    uint32_t M = static_cast<uint32_t>(shapeA.GetDim(0));
    uint32_t K = static_cast<uint32_t>(shapeA.GetDim(1));
    uint32_t N = static_cast<uint32_t>(shapeB.GetDim(1));

    // Fixed small tile sizes for K and N (cube unit works well with 16x16)
    uint32_t tileK = 16;
    uint32_t tileN = 16;
    uint32_t tileM = compute_tileM(M, K, N, tileK, tileN);

    // Choose blockDim to match number of row chunks
    uint32_t numTileM = CeilDiv(M, tileM);
    uint32_t blockDim = numTileM;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_K(K);
    tiling.set_N(N);
    tiling.set_tileM(tileM);
    tiling.set_tileK(tileK);
    tiling.set_tileN(tileN);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

